#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

kernel void bpnn_layerforward_ocl(global float* l1,
                                  global float* l2,
                                  global float* conn_flat,
                                  global float* partial_sum,
                                  local float* local_l1,
                                  local float* local_conn,
                                  int n1,
                                  int n2) {
    int j = get_global_id(0);
    int y = get_global_id(1);

    if (j > n2 || j == 0) return;

    int block_idx = y / BLOCK_SIZE;
    int local_j = get_local_id(0);
    int local_k_idx = get_local_id(1);

    int stride = n2 + 1;

    // Load l1[global_k] into local_l1[local_k_idx]
    int global_k = block_idx * BLOCK_SIZE + local_k_idx;
    if (global_k <= n1) {
        local_l1[local_k_idx] = l1[global_k];
    } else {
        local_l1[local_k_idx] = 0.0f;
    }

    // Load weights conn[global_k][j] into local_conn[local_k_idx][local_j]
    if (global_k <= n1) {
        local_conn[local_k_idx * BLOCK_SIZE + local_j] = conn_flat[global_k * stride + j];
    } else {
        local_conn[local_k_idx * BLOCK_SIZE + local_j] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += local_conn[k * BLOCK_SIZE + local_j] * local_l1[k];
    }

    // Store partial sum for this j and block
    // Host expects partial_sum[block_idx * n2 + (j-1)]
    partial_sum[block_idx * n2 + (j-1)] = sum;
}

kernel void bpnn_adjust_weights_ocl(global float* delta,
                                    int ndelta,
                                    global float* ly,
                                    int nly,
                                    global float* w_flat,
                                    global float* oldw_flat) {
    int j = get_global_id(0);
    int k = get_global_id(1);

    if (j > ndelta || j == 0) return;
    if (k > nly) return;

    int idx = k * (ndelta + 1) + j;

    float delta_val = delta[j];
    float ly_val = (k == 0) ? 1.0f : ly[k];

    float old_dw = oldw_flat[idx];
    float new_dw = (ETA * delta_val * ly_val) + (MOMENTUM * old_dw);

    w_flat[idx] += new_dw;
    oldw_flat[idx] = new_dw;
}
